mapper.sql:
from aiw_user u
where u.is_deleted = 0
and u.status = #{criteria.status.code}

    and (lower(u.user_no) like concat('%', lower(#{criteria.keyword}), '%')
    or exists (
        select 1 from aiw_user_identity i
        where i.user_biz_id = u.biz_id and i.is_deleted = 0
          and lower(i.identity_value) like concat('%', lower(#{criteria.keyword}), '%')
    ))


    and exists (
        select 1 from aiw_user_risk_profile r
        where r.user_biz_id = u.biz_id and r.is_deleted = 0
          and r.kyc_status = #{criteria.kycStatus.code}
    )


    and exists (
        select 1 from aiw_user_risk_profile r
        where r.user_biz_id = u.biz_id and r.is_deleted = 0
          and r.risk_level = #{criteria.riskLevel}
    )

mapper.select:
select u.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
